  array('id' => '19','user_id' => '10001','category_id' => '30','return_policy' => '3','category_path' => '5,27,30','title' => 'Woofers Speakers by Sander Mulder','description' => '<p style="margin: 0px; padding: 0px 0px 10px; border: 0px; font-size: 13px; vertical-align: baseline; list-style: none; quotes: none; font-style: normal; outline: none; line-height: 18px; color: #383d48; font-weight: normal; font-family: \'Helvetica Neue\', Helvetica, Arial, sans-serif; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; background-color: #ffffff; text-decoration-style: initial; text-decoration-color: initial;">Woofers Speakers by Sander Mulder are definitely extraordinary speakers.</p>
<p style="margin: 0px; padding: 0px 0px 10px; border: 0px; font-size: 13px; vertical-align: baseline; list-style: none; quotes: none; font-style: normal; outline: none; line-height: 18px; color: #383d48; font-weight: normal; font-family: \'Helvetica Neue\', Helvetica, Arial, sans-serif; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; background-color: #ffffff; text-decoration-style: initial; text-decoration-color: initial;">This is functional kitsch; the wrong becomes the new right. By adding a function to an otherwise grotesque object, it acquires new aesthetic values, becoming an object of desire. Pun intended; these woofers hold the midst between a loyal 4 footed companion and an addition to your sound system.</p>
<p style="margin: 0px; padding: 0px 0px 10px; border: 0px; font-size: 13px; vertical-align: baseline; list-style: none; quotes: none; font-style: normal; outline: none; line-height: 18px; color: #383d48; font-weight: normal; font-family: \'Helvetica Neue\', Helvetica, Arial, sans-serif; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; background-color: #ffffff; text-decoration-style: initial; text-decoration-color: initial;"><span style="margin: 0px; padding: 0px; border: 0px; font-size: 13px; vertical-align: baseline; list-style: none; quotes: none; font-style: normal; outline: none; font-weight: normal !important;">The “Woofer” speaker system contains custom engineered electronic filters and sounds remarkably well compared to your everyday speaker set.</span></p>
<p style="margin: 0px; padding: 0px 0px 10px; border: 0px; font-size: 13px; vertical-align: baseline; list-style: none; quotes: none; font-style: normal; outline: none; line-height: 18px; color: #383d48; font-weight: normal; font-family: \'Helvetica Neue\', Helvetica, Arial, sans-serif; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; background-color: #ffffff; text-decoration-style: initial; text-decoration-color: initial;">A coaxial speaker system consisting of 2 dogs.</p>
<p style="margin: 0px; padding: 0px 0px 10px; border: 0px; font-size: 13px; vertical-align: baseline; list-style: none; quotes: none; font-style: normal; outline: none; line-height: 18px; color: #383d48; font-weight: normal; font-family: \'Helvetica Neue\', Helvetica, Arial, sans-serif; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; background-color: #ffffff; text-decoration-style: initial; text-decoration-color: initial;">Indoor use only.</p>
<p style="margin: 0px; padding: 0px 0px 10px; border: 0px; font-size: 13px; vertical-align: baseline; list-style: none; quotes: none; font-style: normal; outline: none; line-height: 18px; color: #383d48; font-weight: normal; font-family: \'Helvetica Neue\', Helvetica, Arial, sans-serif; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; background-color: #ffffff; text-decoration-style: initial; text-decoration-color: initial;">51 x 43 x 29 cm./ <span style="margin: 0px; padding: 0px; border: 0px; font-size: 13px; vertical-align: baseline; list-style: none; quotes: none; font-style: normal; outline: none; font-weight: normal !important;">Weight: 8kg.</span></p>
