  array('id' => '27','user_id' => '10001','category_id' => '7','return_policy' => '1','category_path' => '7','title' => 'Food Huggers Silicone Food Savers','description' => '<p style="margin: 0px; padding: 0px 0px 10px; border: 0px; font-size: 13px; vertical-align: baseline; list-style: none; quotes: none; font-style: normal; outline: none; line-height: 18px; color: #383d48; font-weight: normal; font-family: \'Helvetica Neue\', Helvetica, Arial, sans-serif; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; background-color: #ffffff; text-decoration-style: initial; text-decoration-color: initial;">Food Huggers keep your fruits and veggies fresh longer.</p>
