  array('id' => '28','user_id' => '10001','category_id' => '7','return_policy' => '1','category_path' => '7','title' => 'Copco Bag Cap','description' => '<p style="margin: 0px; padding: 0px 0px 10px; border: 0px; font-size: 13px; vertical-align: baseline; list-style: none; quotes: none; font-style: normal; outline: none; line-height: 18px; color: #383d48; font-weight: normal; font-family: \'Helvetica Neue\', Helvetica, Arial, sans-serif; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; background-color: #ffffff; text-decoration-style: initial; text-decoration-color: initial;">The Bag Cap seals in the freshness of bagged foods without removing the item from its original packaging so you still have the directions for use and the nutrition facts.</p>
<p style="margin: 0px; padding: 0px 0px 10px; border: 0px; font-size: 13px; vertical-align: baseline; list-style: none; quotes: none; font-style: normal; outline: none; line-height: 18px; color: #383d48; font-weight: normal; font-family: \'Helvetica Neue\', Helvetica, Arial, sans-serif; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; background-color: #ffffff; text-decoration-style: initial; text-decoration-color: initial;">Simply attach the two-piece Bag Cap to your open bag, then when you need some chips, candy, frozen vegetables or grains, simply flip open the cap and pour out as much or as little as you need. After you’re done, snap the cap closed and store.</p>
<p style="margin: 0px; padding: 0px 0px 10px; border: 0px; font-size: 13px; vertical-align: baseline; list-style: none; quotes: none; font-style: normal; outline: none; line-height: 18px; color: #383d48; font-weight: normal; font-family: \'Helvetica Neue\', Helvetica, Arial, sans-serif; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; background-color: #ffffff; text-decoration-style: initial; text-decoration-color: initial;">The Bag Cap is refrigerator, freezer and dishwasher safe so it\'s perfect for any bag you need to store.</p>
<p style="margin: 0px; padding: 0px 0px 10px; border: 0px; font-size: 13px; vertical-align: baseline; list-style: none; quotes: none; font-style: normal; outline: none; line-height: 18px; color: #383d48; font-weight: normal; font-family: \'Helvetica Neue\', Helvetica, Arial, sans-serif; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; background-color: #ffffff; text-decoration-style: initial; text-decoration-color: initial;">- Large: 5.2 x 4 x 2.2 inches</p>
<p style="margin: 0px; padding: 0px 0px 10px; border: 0px; font-size: 13px; vertical-align: baseline; list-style: none; quotes: none; font-style: normal; outline: none; line-height: 18px; color: #383d48; font-weight: normal; font-family: \'Helvetica Neue\', Helvetica, Arial, sans-serif; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; background-color: #ffffff; text-decoration-style: initial; text-decoration-color: initial;">- Medium: 3.5 x 2.5 x 2 inches</p>','total_quantity' => '5','sold' => '0','exchange_policy' => '1','policy_description' => '','video_mp4' => NULL,'video_webm' => NULL,'video_thumb' => NULL,'views_count' => '0','likes_count' => '0','status' => 'Active','admin_status' => 'Approved','sold_out' => 'No','cash_on_store' => 'No','cash_on_delivery' => 'No','is_featured' => 'No','is_popular' => 'No','is_recommend' => 'No','is_editor' => 'No','is_header' => 'No','created_at' => '2017-09-19 20:48:36','updated_at' => '2020-01-31 19:49:07'),
  array('id' => '30','user_id' => '10001','category_id' => '7','return_policy' => '1','category_path' => '7','title' => 'Rosle Kitchen Torch','description' => '<p style="margin: 0px; padding: 0px 0px 10px; border: 0px; font-size: 13px; vertical-align: baseline; list-style: none; quotes: none; font-style: normal; outline: none; line-height: 18px; color: #383d48; font-weight: normal; font-family: \'Helvetica Neue\', Helvetica, Arial, sans-serif; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; background-color: #ffffff; text-decoration-style: initial; text-decoration-color: initial;">Crème brûlée does not have to be reserved for meals out, enjoy this delicious dessert (and other dishes) at home with the Rosle Kitchen Torch.</p>
